        ("code", "// Crear la sesión de cobro (backend)\nconst session = await stripe.checkout.sessions.create({\n  mode: 'payment',\n  line_items: [{\n    price_data: {\n      currency: 'usd',\n      product_data: { name: 'Paquete de 100 fichas' },\n      unit_amount: 500,           // centavos: $5.00\n    },\n    quantity: 1,\n  }],\n  success_url: 'https://miapp.com/compra/exito',\n  cancel_url: 'https://miapp.com/compra/cancelado',\n}, { idempotencyKey: ordenId })  // reintento seguro\n\nreturn c.json({ url: session.url })"),
